svg.script:

(function() {
  var svg = document.getElementById('Layer_1');
  var layer = document.getElementById('anim-layer');
  var ns = 'http://www.w3.org/2000/svg';

  // Build adjacency from actual edges
  var lines = svg.querySelectorAll('line');
  var adj = {};
  var nodeSet = {};

  function key(x, y) { return Math.round(x*10)/10 + ',' + Math.round(y*10)/10; }

  for (var i = 0; i < lines.length; i++) {
    var l = lines[i];
    var a = key(parseFloat(l.getAttribute('x1')), parseFloat(l.getAttribute('y1')));
    var b = key(parseFloat(l.getAttribute('x2')), parseFloat(l.getAttribute('y2')));
    if (!adj[a]) adj[a] = [];
    if (!adj[b]) adj[b] = [];
    adj[a].push(b);
    adj[b].push(a);
    nodeSet[a] = true;
    nodeSet[b] = true;
  }

  // Categorise nodes by connectivity
  var nodes = Object.keys(adj);
  var hubs = nodes.filter(function(n) { return adj[n].length >= 6; });
  if (hubs.length === 0) hubs = nodes.slice(0, 5);

  function parseKey(k) { var p = k.split(','); return [parseFloat(p[0]), parseFloat(p[1])]; }

  // Distance between two node keys
  function dist(a, b) {
    var pa = parseKey(a), pb = parseKey(b);
    var dx = pa[0]-pb[0], dy = pa[1]-pb[1];
    return Math.sqrt(dx*dx+dy*dy);
  }

  // Find circle element at position
  var circles = svg.querySelectorAll('circle.cls-1');
  var circleMap = {};
  for (var i = 0; i < circles.length; i++) {
    var c = circles[i];
    var ck = key(parseFloat(c.getAttribute('cx')), parseFloat(c.getAttribute('cy')));
    circleMap[ck] = c;
  }

  function flashNode(nk, duration) {
    var pos = parseKey(nk);
    var circ = circleMap[nk];
    var r = circ ? parseFloat(circ.getAttribute('r')) : 3;
    var flash = document.createElementNS(ns, 'circle');
    flash.setAttribute('cx', pos[0]);
    flash.setAttribute('cy', pos[1]);
    flash.setAttribute('r', r + 3);
    flash.setAttribute('class', 'node-flash');
    layer.appendChild(flash);

    if (circ) {
      circ._flashCount = (circ._flashCount || 0) + 1;
      circ.style.fill = '#3366FF';
      circ.style.stroke = '#3366FF';
    }

    // Dwell at full blue for 70% of duration, then fast fade
    flash.style.opacity = '0.7';
    setTimeout(function() { flash.style.opacity = '0.5'; }, duration * 0.7);
    setTimeout(function() {
      flash.style.opacity = '0';
      if (circ) {
        circ._flashCount--;
        if (circ._flashCount <= 0) {
          circ._flashCount = 0;
          circ.style.fill = '#C5C3BF';
          circ.style.stroke = '#C5C3BF';
        }
      }
      setTimeout(function() { if (flash.parentNode) layer.removeChild(flash); }, 150);
    }, duration * 0.85);
  }

  function traceEdge(fromKey, toKey, duration, cb) {
    var p1 = parseKey(fromKey);
    var p2 = parseKey(toKey);
    var line = document.createElementNS(ns, 'line');
    line.setAttribute('x1', p1[0]);
    line.setAttribute('y1', p1[1]);
    line.setAttribute('x2', p1[0]);
    line.setAttribute('y2', p1[1]);
    line.setAttribute('class', 'edge-trace');
    layer.appendChild(line);

    flashNode(fromKey, duration + 1800);

    var start = null;
    function animate(ts) {
      if (!start) start = ts;
      var t = Math.min((ts - start) / duration, 1);
      var ease = t < 0.5 ? 2*t*t : -1+(4-2*t)*t;
      line.setAttribute('x2', p1[0] + (p2[0]-p1[0]) * ease);
      line.setAttribute('y2', p1[1] + (p2[1]-p1[1]) * ease);
      if (t < 1) { requestAnimationFrame(animate); }
      else {
        flashNode(toKey, 1800);
        if (cb) cb();
      }
    }
    requestAnimationFrame(animate);

    // Dwell in blue for 2s after trace, then fast fade
    setTimeout(function() {
      line.style.transition = 'opacity 0.5s';
      line.style.opacity = '0';
      setTimeout(function() { if (line.parentNode) layer.removeChild(line); }, 600);
    }, duration + 2000);
  }

  // BFS to find path between two distant nodes
  function findPath(from, to, maxDepth) {
    var queue = [[from]];
    var visited = {};
    visited[from] = true;
    while (queue.length > 0) {
      var path = queue.shift();
      if (path.length > maxDepth) return null;
      var cur = path[path.length - 1];
      if (cur === to) return path;
      var neighbors = adj[cur] || [];
      for (var i = 0; i < neighbors.length; i++) {
        if (!visited[neighbors[i]]) {
          visited[neighbors[i]] = true;
          queue.push(path.concat(neighbors[i]));
        }
      }
    }
    return null;
  }

  // Pattern: constellation — pick scattered nodes, connect them via paths
  function constellation(delay) {
    // Pick 4-7 spread-out hub/large nodes as "stars" of the constellation
    var shuffled = hubs.slice().sort(function() { return Math.random() - 0.5; });
    var starCount = 4 + Math.floor(Math.random() * 4); // 4-7 stars
    var stars = [];
    for (var i = 0; i < shuffled.length && stars.length < starCount; i++) {
      // Ensure spread: each star should be far from existing ones
      var dominated = false;
      for (var j = 0; j < stars.length; j++) {
        if (dist(shuffled[i], stars[j]) < 80) { dominated = true; break; }
      }
      if (!dominated) stars.push(shuffled[i]);
    }
    if (stars.length < 3) stars = shuffled.slice(0, 4);

    setTimeout(function() {
      // Connect stars with forking — trace path, then fork branches at midpoints
      var idx = 0;
      var visited = {};
      function connectNext() {
        if (idx >= stars.length - 1) return;
        var path = findPath(stars[idx], stars[idx + 1], 8);
        if (path && path.length >= 3) {
          var step = 0;
          path.forEach(function(n) { visited[n] = true; });
          function traceStep() {
            if (step >= path.length - 1) {
              idx++;
              setTimeout(connectNext, 100);
              return;
            }
            traceEdge(path[step], path[step + 1], 200, function() {
              var current = path[step + 1];
              // Fork: at some nodes, branch off to 1-2 unvisited neighbors
              if (Math.random() < 0.5 && adj[current]) {
                var forks = (adj[current] || []).filter(function(n) { return !visited[n]; });
                var forkTargets = forks.slice(0, 2);
                forkTargets.forEach(function(ft, fi) {
                  visited[ft] = true;
                  setTimeout(function() {
                    traceEdge(current, ft, 200, function() {
                      // Extend fork one more hop
                      var ext = (adj[ft] || []).filter(function(n) { return !visited[n]; });
                      if (ext.length > 0) {
                        visited[ext[0]] = true;
                        setTimeout(function() { traceEdge(ft, ext[0], 200); }, 80);
                      }
                    });
                  }, fi * 80);
                });
              }
              step++;
              setTimeout(traceStep, 50);
            });
          }
          traceStep();
        } else {
          idx++;
          connectNext();
        }
      }
      connectNext();
    }, delay);
  }

  // Pattern: long chain — walk 6-10 hops through the graph
  function longChain(startNode, depth, delay) {
    var current = startNode;
    var visited = {};
    visited[current] = true;
    var step = 0;

    function next() {
      if (step >= depth) return;
      var neighbors = (adj[current] || []).filter(function(n) { return !visited[n]; });
      if (neighbors.length === 0) return;
      // Prefer neighbors that lead to further-away nodes (spread out)
      neighbors.sort(function(a, b) { return dist(startNode, b) - dist(startNode, a); });
      var target = neighbors[Math.random() < 0.7 ? 0 : Math.floor(Math.random() * neighbors.length)];
      visited[target] = true;
      traceEdge(current, target, 250, function() {
        current = target;
        step++;
        setTimeout(next, 80);
      });
    }
    setTimeout(next, delay);
  }

  // Pattern: star burst from hub, then secondary bursts from leaves
  function cascadeStar(hubNode, delay) {
    var neighbors = (adj[hubNode] || []).slice().sort(function() { return Math.random() - 0.5; });
    var targets = neighbors.slice(0, Math.min(5, neighbors.length));

    setTimeout(function() {
      flashNode(hubNode, 2000);
      var visited = {};
      visited[hubNode] = true;
      targets.forEach(function(t) { visited[t] = true; });

      targets.forEach(function(t, i) {
        setTimeout(function() {
          traceEdge(hubNode, t, 250, function() {
            // Secondary burst from this leaf
            var leafNeighbors = (adj[t] || []).filter(function(n) { return !visited[n]; });
            var secondary = leafNeighbors.slice(0, 2);
            secondary.forEach(function(s, si) {
              visited[s] = true;
              setTimeout(function() { traceEdge(t, s, 200); }, si * 60);
            });
          });
        }, i * 60);
      });
    }, delay);
  }

  // Pattern: cross-graph bridge — connect two distant hubs via shortest path
  function bridge(delay) {
    // Find two hubs that are far apart
    var best = null, bestDist = 0;
    for (var i = 0; i < hubs.length; i++) {
      for (var j = i + 1; j < hubs.length; j++) {
        var d = dist(hubs[i], hubs[j]);
        if (d > bestDist) { bestDist = d; best = [hubs[i], hubs[j]]; }
      }
    }
    if (!best) return;

    // Randomly pick from top 3 farthest pairs for variety
    var pairs = [];
    for (var i = 0; i < hubs.length; i++) {
      for (var j = i + 1; j < hubs.length; j++) {
        pairs.push({ a: hubs[i], b: hubs[j], d: dist(hubs[i], hubs[j]) });
      }
    }
    pairs.sort(function(a, b) { return b.d - a.d; });
    var pick = pairs[Math.floor(Math.random() * Math.min(3, pairs.length))];

    var path = findPath(pick.a, pick.b, 12);
    if (!path || path.length < 4) return;

    setTimeout(function() {
      var step = 0;
      function traceStep() {
        if (step >= path.length - 1) return;
        traceEdge(path[step], path[step + 1], 200, function() {
          step++;
          setTimeout(traceStep, 50);
        });
      }
      traceStep();
    }, delay);
  }

  // Continuous overlapping animations — fire a new pattern every 1.5s
  var patterns = [
    function() { constellation(0); },
    function() { var h = hubs[Math.floor(Math.random()*hubs.length)]; longChain(h, 8, 0); },
    function() { var h = hubs[Math.floor(Math.random()*hubs.length)]; cascadeStar(h, 0); },
    function() { bridge(0); },
    function() { constellation(0); },
    function() { var h = hubs[Math.floor(Math.random()*hubs.length)]; longChain(h, 10, 0); },
    function() { var h = hubs[Math.floor(Math.random()*hubs.length)]; cascadeStar(h, 0); },
    function() { bridge(0); }
  ];
  var patIdx = 0;

  function fireNext() {
    patterns[patIdx % patterns.length]();
    patIdx++;
  }

  // Start immediately, overlap patterns every 1.5s
  setTimeout(function() {
    fireNext();
    setInterval(fireNext, 1500);
  }, 200);
})();
